9	// specific language governing permissions and limitations under the License.
10	//
11	// Authors:
12	// - Matheus Cavalcante <matheusd@iis.ee.ethz.ch>
13	
14	// Description:
15	// Data width upsize conversion.
16	// Connects a narrow master to a wider slave.
17	
18	// NOTE: The upsizer does not support WRAP bursts, and will answer with SLVERR
19	// upon receiving a burst of such type.
20	
21	module axi_dw_upsizer #(
22	    parameter int unsigned AxiMaxReads         = 1    , // Number of outstanding reads
23	    parameter int unsigned AxiSlvPortDataWidth = 8    , // Data width of the slv port
24	    parameter int unsigned AxiMstPortDataWidth = 8    , // Data width of the mst port
25	    parameter int unsigned AxiAddrWidth        = 1    , // Address width
26	    parameter int unsigned AxiIdWidth          = 1    , // ID width
27	    parameter type aw_chan_t                   = logic, // AW Channel Type
28	    parameter type mst_w_chan_t                = logic, //  W Channel Type for mst port
29	    parameter type slv_w_chan_t                = logic, //  W Channel Type for slv port
30	    parameter type b_chan_t                    = logic, //  B Channel Type
31	    parameter type ar_chan_t                   = logic, // AR Channel Type
32	    parameter type mst_r_chan_t                = logic, //  R Channel Type for mst port
33	    parameter type slv_r_chan_t                = logic, //  R Channel Type for slv port
34	    parameter type axi_mst_req_t               = logic, // AXI Request Type for mst ports
35	    parameter type axi_mst_resp_t              = logic, // AXI Response Type for mst ports
36	    parameter type axi_slv_req_t               = logic, // AXI Request Type for slv ports
37	    parameter type axi_slv_resp_t              = logic  // AXI Response Type for slv ports
38	  ) (
39	    input  logic          clk_i,
40	    input  logic          rst_ni,
41	    // Slave interface
42	    input  axi_slv_req_t  slv_req_i,
43	    output axi_slv_resp_t slv_resp_o,
44	    // Master interface
45	    output axi_mst_req_t  mst_req_o,
46	    input  axi_mst_resp_t mst_resp_i
47	  );
48	
49	  /*****************
50	   *  DEFINITIONS  *
51	   *****************/
52	  import axi_pkg::aligned_addr;
53	  import axi_pkg::beat_addr   ;
54	  import axi_pkg::modifiable  ;
55	
56	  import cf_math_pkg::idx_width;
57	
58	  // Type used to index which adapter is handling each outstanding transaction.
59	  localparam TranIdWidth = AxiMaxReads > 1 ? $clog2(AxiMaxReads) : 1;
60	  typedef logic [TranIdWidth-1:0] tran_id_t;
61	
62	  // Data width
63	  localparam AxiSlvPortStrbWidth = AxiSlvPortDataWidth / 8;
64	  localparam AxiMstPortStrbWidth = AxiMstPortDataWidth / 8;
65	
66	  localparam AxiSlvPortMaxSize = $clog2(AxiSlvPortStrbWidth);
67	  localparam AxiMstPortMaxSize = $clog2(AxiMstPortStrbWidth);
68	
69	  // Byte-grouped data words
70	  typedef logic [AxiMstPortStrbWidth-1:0][7:0] mst_data_t;
71	  typedef logic [AxiSlvPortStrbWidth-1:0][7:0] slv_data_t;
72	
73	  // Address width
74	  typedef logic [AxiAddrWidth-1:0] addr_t;
75	
76	  // ID width
77	  typedef logic [AxiIdWidth-1:0] id_t;
78	
79	  // Length of burst after upsizing
80	  typedef logic [$clog2(AxiMstPortStrbWidth/AxiSlvPortStrbWidth) + 7:0] burst_len_t;
81	
82	  // Internal AXI bus
83	  axi_mst_req_t  mst_req;
84	  axi_mst_resp_t mst_resp;
85	
86	  /**************
87	   *  ARBITERS  *
88	   **************/
89	
90	  // R
91	
92	  slv_r_chan_t [AxiMaxReads-1:0] slv_r_tran;
93	  logic        [AxiMaxReads-1:0] slv_r_valid_tran;
94	  logic        [AxiMaxReads-1:0] slv_r_ready_tran;
95	
96	  rr_arb_tree #(
97	    .NumIn    (AxiMaxReads ),
98	    .DataType (slv_r_chan_t),
99	    .AxiVldRdy(1'b1        ),
100	    .ExtPrio  (1'b0        ),
101	    .LockIn   (1'b1        )
102	  ) i_slv_r_arb (
103	    .clk_i  (clk_i             ),
104	    .rst_ni (rst_ni            ),
105	    .flush_i(1'b0              ),
106	    .rr_i   ('0                ),
107	    .req_i  (slv_r_valid_tran  ),
108	    .gnt_o  (slv_r_ready_tran  ),
109	    .data_i (slv_r_tran        ),
110	    .gnt_i  (slv_req_i.r_ready ),
111	    .req_o  (slv_resp_o.r_valid),
112	    .data_o (slv_resp_o.r      ),
113	    .idx_o  (/* Unused */      )
114	  );
115	
116	  logic [AxiMaxReads-1:0] mst_r_ready_tran;
117	  assign mst_req.r_ready = |mst_r_ready_tran;
118	
119	  // AR
120	
121	  id_t                    arb_slv_ar_id;
122	  logic                   arb_slv_ar_req;
123	  logic                   arb_slv_ar_gnt;
124	  logic [AxiMaxReads-1:0] arb_slv_ar_gnt_tran;
125	  // Multiplex AR slave between AR and AW for the injection of atomic operations with an R response.
126	  logic                   inject_aw_into_ar;
127	  logic                   inject_aw_into_ar_req;
128	  logic                   inject_aw_into_ar_gnt;
129	
130	  assign arb_slv_ar_gnt = |arb_slv_ar_gnt_tran;
131	
132	  rr_arb_tree #(
133	    .NumIn     (2         ),
134	    .DataWidth (AxiIdWidth),
135	    .ExtPrio   (1'b0      ),
136	    .AxiVldRdy (1'b1      ),
137	    .LockIn    (1'b0      )
138	  ) i_slv_ar_arb (
139	    .clk_i  (clk_i                                       ),
140	    .rst_ni (rst_ni                                      ),
141	    .flush_i(1'b0                                        ),
142	    .rr_i   ('0                                          ),
143	    .req_i  ({inject_aw_into_ar_req, slv_req_i.ar_valid} ),
144	    .gnt_o  ({inject_aw_into_ar_gnt, slv_resp_o.ar_ready}),
145	    .data_i ({slv_req_i.aw.id, slv_req_i.ar.id}          ),
146	    .req_o  (arb_slv_ar_req                              ),
147	    .gnt_i  (arb_slv_ar_gnt                              ),
148	    .data_o (arb_slv_ar_id                               ),
149	    .idx_o  (inject_aw_into_ar                           )
150	  );
151	
152	  ar_chan_t [AxiMaxReads-1:0] mst_ar_tran;
153	  id_t      [AxiMaxReads-1:0] mst_ar_id;
154	  logic     [AxiMaxReads-1:0] mst_ar_valid_tran;
155	  logic     [AxiMaxReads-1:0] mst_ar_ready_tran;
156	  tran_id_t                   mst_req_idx;
157	
158	  rr_arb_tree #(
159	    .NumIn    (AxiMaxReads),
160	    .DataType (ar_chan_t  ),
161	    .AxiVldRdy(1'b1       ),
162	    .ExtPrio  (1'b0       ),
163	    .LockIn   (1'b1       )
164	  ) i_mst_ar_arb (
165	    .clk_i  (clk_i            ),
166	    .rst_ni (rst_ni           ),
167	    .flush_i(1'b0             ),
168	    .rr_i   ('0               ),
169	    .req_i  (mst_ar_valid_tran),
170	    .gnt_o  (mst_ar_ready_tran),
171	    .data_i (mst_ar_tran      ),
172	    .gnt_i  (mst_resp.ar_ready),
173	    .req_o  (mst_req.ar_valid ),
174	    .data_o (mst_req.ar       ),
175	    .idx_o  (mst_req_idx      )
176	  );
177	
178	  /*****************
179	   *  ERROR SLAVE  *
180	   *****************/
181	
182	  axi_mst_req_t  axi_err_req;
183	  axi_mst_resp_t axi_err_resp;
184	
185	  axi_err_slv #(
186	    .AxiIdWidth(AxiIdWidth          ),
187	    .Resp      (axi_pkg::RESP_SLVERR),
188	    .axi_req_t (axi_mst_req_t       ),
189	    .axi_resp_t(axi_mst_resp_t      )
190	  ) i_axi_err_slv (
191	    .clk_i     (clk_i       ),
192	    .rst_ni    (rst_ni      ),
193	    .test_i    (1'b0        ),
194	    .slv_req_i (axi_err_req ),
195	    .slv_resp_o(axi_err_resp)
196	  );
197	
198	  /***********
199	   *  DEMUX  *
200	   ***********/
201	
202	  // Requests can be sent either to the error slave,
203	  // or to the DWC's master port.
204	
205	  logic [AxiMaxReads-1:0] mst_req_ar_err;
206	  logic                   mst_req_aw_err;
207	
208	  axi_demux #(
209	    .AxiIdWidth (AxiIdWidth    ),
210	    .AxiLookBits(AxiIdWidth    ),
211	    .aw_chan_t  (aw_chan_t     ),
212	    .w_chan_t   (mst_w_chan_t  ),
213	    .b_chan_t   (b_chan_t      ),
214	    .ar_chan_t  (ar_chan_t     ),
215	    .r_chan_t   (mst_r_chan_t  ),
216	    .axi_req_t  (axi_mst_req_t ),
217	    .axi_resp_t (axi_mst_resp_t),
218	    .NoMstPorts (2             ),
219	    .MaxTrans   (AxiMaxReads   ),
220	    .SpillAw    (1'b1          ) // Required to break dependency between AW and W channels
221	  ) i_axi_demux (
222	    .clk_i          (clk_i                      ),
223	    .rst_ni         (rst_ni                     ),
224	    .test_i         (1'b0                       ),
225	    .mst_reqs_o     ({axi_err_req, mst_req_o}   ),
226	    .mst_resps_i    ({axi_err_resp, mst_resp_i} ),
227	    .slv_ar_select_i(mst_req_ar_err[mst_req_idx]),
228	    .slv_aw_select_i(mst_req_aw_err             ),
229	    .slv_req_i      (mst_req                    ),
230	    .slv_resp_o     (mst_resp                   )
231	  );
232	
233	  /**********
234	   *  READ  *
235	   **********/
236	
237	  typedef enum logic [1:0] {
238	    R_IDLE       ,
239	    R_INJECT_AW  ,
240	    R_PASSTHROUGH,
241	    R_INCR_UPSIZE
242	  } r_state_e;
243	
244	  // Write-related type, but w_req_q is referenced from Read logic
245	  typedef struct packed {
246	    aw_chan_t aw                ;
247	    logic aw_valid              ;
248	    logic aw_throw_error        ;
249	    mst_w_chan_t w              ;
250	    logic w_valid               ;
251	    axi_pkg::len_t burst_len    ;
252	    axi_pkg::size_t orig_aw_size;
253	  } w_req_t;
254	
255	  w_req_t   w_req_d, w_req_q;
256	
257	  // Decide which upsizer will handle the incoming AXI transaction
258	  logic     [AxiMaxReads-1:0] idle_read_upsizer;
259	  tran_id_t                   idx_ar_upsizer ;
260	
261	  // Find an idle upsizer to handle this transaction
262	  tran_id_t idx_idle_upsizer;
263	  lzc #(
264	    .WIDTH(AxiMaxReads)
265	  ) i_idle_lzc (
266	    .in_i   (idle_read_upsizer),
267	    .cnt_o  (idx_idle_upsizer ),
268	    .empty_o(/* Unused */     )
269	  );
270	
271	  // Is there already another upsizer handling a transaction with the same id
272	  logic     [AxiMaxReads-1:0] id_clash_upsizer;
273	  tran_id_t                   idx_id_clash_upsizer ;
274	  for (genvar t = 0; t < AxiMaxReads; t++) begin: gen_id_clash
275	    assign id_clash_upsizer[t] = arb_slv_ar_id == mst_ar_id[t] && !idle_read_upsizer[t];
276	  end
277	
278	  onehot_to_bin #(
279	    .ONEHOT_WIDTH(AxiMaxReads)
280	  ) i_id_clash_onehot_to_bin (
281	    .onehot(id_clash_upsizer    ),
282	    .bin   (idx_id_clash_upsizer)
283	  );
284	
285	  // Choose an idle upsizer, unless there is an id clash
286	  assign idx_ar_upsizer = (|id_clash_upsizer) ? idx_id_clash_upsizer : idx_idle_upsizer;
287	
288	  // This logic is used to resolve which upsizer is handling
289	  // each outstanding read transaction
290	
291	  logic     r_upsizer_valid;
292	  tran_id_t idx_r_upsizer;
293	
294	  logic [AxiMaxReads-1:0] rid_upsizer_match;
295	
296	  // Is there a upsizer handling this transaction?
297	  assign r_upsizer_valid = |rid_upsizer_match;
298	
299	  for (genvar t = 0; t < AxiMaxReads; t++) begin: gen_rid_match
300	    assign rid_upsizer_match[t] = (mst_resp.r.id == mst_ar_id[t]) && !idle_read_upsizer[t];
301	  end
302	
303	  onehot_to_bin #(
304	    .ONEHOT_WIDTH(AxiMaxReads)
305	  ) i_rid_upsizer_lzc (
306	    .onehot(rid_upsizer_match),
307	    .bin   (idx_r_upsizer    )
308	  );
309	
310	  typedef struct packed {
311	    ar_chan_t ar                ;
312	    logic ar_valid              ;
313	    logic ar_throw_error        ;
314	    axi_pkg::len_t burst_len    ;
315	    axi_pkg::size_t orig_ar_size;
316	  } r_req_t;
317	
318	  for (genvar t = 0; unsigned'(t) < AxiMaxReads; t++) begin: gen_read_upsizer
319	    r_state_e r_state_d, r_state_q;
320	    r_req_t r_req_d    , r_req_q  ;
321	
322	    // Are we idle?
323	    assign idle_read_upsizer[t] = (r_state_q == R_IDLE) || (r_state_q == R_INJECT_AW);
324	
325	    // Byte-grouped data signal for the lane steering step
326	    slv_data_t r_data;
327	
328	    always_comb begin
329	      // Maintain state
330	      r_state_d = r_state_q;
331	      r_req_d   = r_req_q  ;
332	
333	      // AR Channel
334	      mst_ar_tran[t]       = r_req_q.ar      ;
335	      mst_ar_id[t]         = r_req_q.ar.id   ;
336	      mst_ar_valid_tran[t] = r_req_q.ar_valid;
337	
338	      // Throw an error
339	      mst_req_ar_err[t] = r_req_q.ar_throw_error;
340	
341	      // R Channel
342	      // No latency
343	      slv_r_tran[t]      = '0             ;
344	      slv_r_tran[t].id   = mst_resp.r.id  ;
345	      slv_r_tran[t].resp = mst_resp.r.resp;
346	      slv_r_tran[t].user = mst_resp.r.user;
347	
348	      arb_slv_ar_gnt_tran[t] = 1'b0;
349	
350	      mst_r_ready_tran[t] = 1'b0;
351	      slv_r_valid_tran[t] = 1'b0;
352	
353	      // Got a grant on the AR channel
354	      if (mst_ar_valid_tran[t] && mst_ar_ready_tran[t]) begin
355	        r_req_d.ar_valid       = 1'b0;
356	        r_req_d.ar_throw_error = 1'b0;
357	      end
358	
359	      // Initialize r_data
360	      r_data = '0;
361	
362	      unique case (r_state_q)
363	        R_IDLE : begin
364	          // Reset channels
365	          r_req_d.ar = '0;
366	
367	          // New read request
368	          if (arb_slv_ar_req && (idx_ar_upsizer == t)) begin
369	            arb_slv_ar_gnt_tran[t] = 1'b1;
370	
371	            // Must inject an AW request into this upsizer
372	            if (inject_aw_into_ar) begin
373	              r_state_d = R_INJECT_AW;
374	            end else begin
375	              // Default state
376	              r_state_d = R_PASSTHROUGH;
377	
378	              // Save beat
379	              r_req_d.ar           = slv_req_i.ar     ;
380	              r_req_d.ar_valid     = 1'b1             ;
381	              r_req_d.burst_len    = slv_req_i.ar.len ;
382	              r_req_d.orig_ar_size = slv_req_i.ar.size;
383	
384	              unique case (r_req_d.ar.burst)
385	                axi_pkg::BURST_INCR: begin
386	                  // Modifiable transaction
387	                  if (modifiable(r_req_d.ar.cache)) begin
388	                    // No need to upsize single-beat transactions.
389	                    if (r_req_d.ar.len != '0) begin
390	                      // Evaluate output burst length
391	                      automatic addr_t start_addr;
392	                      automatic addr_t end_addr;
393	                      start_addr = aligned_addr(r_req_d.ar.addr, AxiMstPortMaxSize);
394	                      end_addr   = aligned_addr(beat_addr(r_req_d.ar.addr,
395	                          r_req_d.orig_ar_size, r_req_d.burst_len, r_req_d.ar.burst,
396	                          r_req_d.burst_len), AxiMstPortMaxSize);
397	                      r_req_d.ar.len  = (end_addr - start_addr) >> AxiMstPortMaxSize;
398	                      r_req_d.ar.size = AxiMstPortMaxSize                           ;
399	                      r_state_d       = R_INCR_UPSIZE                               ;
400	                    end
401	                  end
402	                end
403	
404	                axi_pkg::BURST_FIXED: begin
405	                  // Passes through the upsizer without any changes
406	                  r_state_d = R_PASSTHROUGH;
407	                end
408	
409	                axi_pkg::BURST_WRAP: begin
410	                  // The DW converter does not support this kind of burst ...
411	                  r_state_d              = R_PASSTHROUGH;
412	                  r_req_d.ar_throw_error = 1'b1         ;
413	
414	                  // ... but might if this is a single-beat transaction
415	                  if (r_req_d.ar.len == '0)
416	                    r_req_d.ar_throw_error = 1'b0;
417	                end
418	
419	                default: ;
420	              endcase
421	            end
422	          end
423	        end
424	
425	        R_INJECT_AW : begin
426	          // Save beat
427	          // During this cycle, w_req_q stores the original AW request
428	          r_req_d.ar.id        = w_req_q.aw.id       ;
429	          r_req_d.ar.addr      = w_req_q.aw.addr     ;
430	          r_req_d.ar.size      = w_req_q.orig_aw_size;
431	          r_req_d.ar.burst     = w_req_q.aw.burst    ;
432	          r_req_d.ar.len       = w_req_q.burst_len   ;
433	          r_req_d.ar.lock      = w_req_q.aw.lock     ;
434	          r_req_d.ar.cache     = w_req_q.aw.cache    ;
435	          r_req_d.ar.prot      = w_req_q.aw.prot     ;
436	          r_req_d.ar.qos       = w_req_q.aw.qos      ;
437	          r_req_d.ar.region    = w_req_q.aw.region   ;
438	          r_req_d.ar.user      = w_req_q.aw.user     ;
439	          r_req_d.ar_valid     = 1'b0                ; // Injected "AR"s from AW are not valid.
440	          r_req_d.burst_len    = w_req_q.burst_len   ;
441	          r_req_d.orig_ar_size = w_req_q.orig_aw_size;
442	
443	          // Default state
444	          r_state_d = R_PASSTHROUGH;
445	
446	          unique case (r_req_d.ar.burst)
447	            axi_pkg::BURST_INCR: begin
448	              // Modifiable transaction
449	              if (modifiable(r_req_d.ar.cache)) begin
450	                // No need to upsize single-beat transactions.
451	                if (r_req_d.ar.len != '0) begin
452	                  // Evaluate output burst length
453	                  automatic addr_t start_addr;
454	                  automatic addr_t end_addr;
455	                  start_addr = aligned_addr(r_req_d.ar.addr, AxiMstPortMaxSize);
456	                  end_addr   = aligned_addr(beat_addr(r_req_d.ar.addr,
457	                      r_req_d.orig_ar_size, r_req_d.burst_len, r_req_d.ar.burst,
458	                      r_req_d.burst_len), AxiMstPortMaxSize);
459	                  r_req_d.ar.len  = (end_addr - start_addr) >> AxiMstPortMaxSize;
460	                  r_req_d.ar.size = AxiMstPortMaxSize                           ;
461	                  r_state_d       = R_INCR_UPSIZE                               ;
462	                end
463	              end
464	            end
465	
466	            axi_pkg::BURST_FIXED: begin
467	              // Passes through the upsizer without any changes
468	              r_state_d = R_PASSTHROUGH;
469	            end
470	
471	            axi_pkg::BURST_WRAP: begin
472	              // The DW converter does not support this kind of burst ...
473	              r_state_d              = R_PASSTHROUGH;
474	              r_req_d.ar_throw_error = 1'b1         ;
475	
476	              // ... but might if this is a single-beat transaction
477	              if (r_req_d.ar.len == '0)
478	                r_req_d.ar_throw_error = 1'b0;
479	            end
480	
481	            default: ;
482	          endcase
483	        end
484	
485	        R_PASSTHROUGH, R_INCR_UPSIZE: begin
486	          // Request was accepted
487	          if (!r_req_q.ar_valid)
488	            if (mst_resp.r_valid && (idx_r_upsizer == t) && r_upsizer_valid) begin
489	              automatic logic [idx_width(AxiMstPortStrbWidth)-1:0] mst_port_offset;
490	              automatic logic [idx_width(AxiSlvPortStrbWidth)-1:0] slv_port_offset;
491	              mst_port_offset = AxiMstPortStrbWidth == 1 ? '0 : r_req_q.ar.addr[idx_width(AxiMstPortStrbWidth)-1:0];
492	              slv_port_offset = AxiSlvPortStrbWidth == 1 ? '0 : r_req_q.ar.addr[idx_width(AxiSlvPortStrbWidth)-1:0];
493	
494	              // Valid output
495	              slv_r_valid_tran[t] = 1'b1                                       ;
496	              slv_r_tran[t].last  = mst_resp.r.last && (r_req_q.burst_len == 0);
497	
498	              // Lane steering
499	              for (int b = 0; b < AxiMstPortStrbWidth; b++) begin
500	                if ((b >= mst_port_offset) &&
501	                    (b - mst_port_offset < (1 << r_req_q.orig_ar_size)) &&
502	                    (b + slv_port_offset - mst_port_offset < AxiSlvPortStrbWidth)) begin
503	                  r_data[b + slv_port_offset - mst_port_offset] = mst_resp.r.data[8*b +: 8];
504	                end
505	              end
506	              slv_r_tran[t].data = r_data;
507	
508	              // Acknowledgment
509	              if (slv_r_ready_tran[t]) begin
510	                r_req_d.burst_len = r_req_q.burst_len - 1;
511	
512	                unique case (r_req_q.ar.burst)
513	                  axi_pkg::BURST_INCR: begin
514	                    r_req_d.ar.addr = aligned_addr(r_req_q.ar.addr, r_req_q.orig_ar_size) + (1 << r_req_q.orig_ar_size);
515	                  end
516	                  axi_pkg::BURST_FIXED: begin
517	                    r_req_d.ar.addr = r_req_q.ar.addr;
518	                  end
519	                  default: ;
520	                endcase
521	
522	                unique case (r_state_q)
523	                  R_PASSTHROUGH:
524	                    mst_r_ready_tran[t] = 1'b1;
525	
526	                  R_INCR_UPSIZE:
527	                    if (r_req_q.burst_len == 0 || (aligned_addr(r_req_d.ar.addr, AxiMstPortMaxSize) != aligned_addr(r_req_q.ar.addr, AxiMstPortMaxSize)))
528	                      mst_r_ready_tran[t] = 1'b1;
529	
530	                  default: ;
531	                endcase
532	
533	                if (r_req_q.burst_len == '0)
534	                  r_state_d = R_IDLE;
535	              end
536	            end
537	        end
538	
539	        default: ;
540	      endcase
541	    end
542	
543	    always_ff @(posedge clk_i or negedge rst_ni) begin
544	      if (!rst_ni) begin
545	        r_state_q <= R_IDLE;
546	        r_req_q   <= '0    ;
547	      end else begin
548	        r_state_q <= r_state_d;
549	        r_req_q   <= r_req_d  ;
550	      end
551	    end
552	  end : gen_read_upsizer
553	
554	  /***********
555	   *  WRITE  *
556	   ***********/
557	
558	  typedef enum logic [1:0] {
559	    W_IDLE       ,
560	    W_PASSTHROUGH,
561	    W_INCR_UPSIZE
562	  } w_state_e;
563	
564	  w_state_e w_state_d, w_state_q;
565	
566	  // Byte-grouped data signal for the serialization step
567	  mst_data_t w_data;
568	
569	  always_comb begin
570	    inject_aw_into_ar_req = 1'b0;
571	
572	    // Maintain state
573	    w_state_d = w_state_q;
574	    w_req_d   = w_req_q  ;
575	
576	    // AW Channel
577	    mst_req.aw          = w_req_q.aw      ;
578	    mst_req.aw_valid    = w_req_q.aw_valid;
579	    slv_resp_o.aw_ready = '0              ;
580	
581	    // Throw an error.
582	    mst_req_aw_err = w_req_q.aw_throw_error;
583	
584	    // W Channel
585	    mst_req.w          = w_req_q.w      ;
586	    mst_req.w_valid    = w_req_q.w_valid;
587	    slv_resp_o.w_ready = '0             ;
588	
589	    // Initialize w_data
590	    w_data = w_req_q.w.data;
591	
592	    // B Channel (No latency)
593	    slv_resp_o.b       = mst_resp.b       ;
594	    slv_resp_o.b_valid = mst_resp.b_valid ;
595	    mst_req.b_ready    = slv_req_i.b_ready;
596	
597	    // Got a grant on the AW channel
598	    if (mst_req.aw_valid && mst_resp.aw_ready) begin
599	      w_req_d.aw_valid       = 1'b0;
600	      w_req_d.aw_throw_error = 1'b0;
601	    end
602	
603	    unique case (w_state_q)
604	      W_PASSTHROUGH, W_INCR_UPSIZE: begin
605	        // Got a grant on the W channel
606	        if (mst_req.w_valid && mst_resp.w_ready) begin
607	          w_data          = '0  ;
608	          w_req_d.w       = '0  ;
609	          w_req_d.w_valid = 1'b0;
610	        end
611	
612	        // Request was accepted
613	        if (!w_req_q.aw_valid) begin
614	          // Ready if downstream interface is idle, or if it is ready
615	          slv_resp_o.w_ready = ~mst_req.w_valid || mst_resp.w_ready;
616	
617	          if (slv_req_i.w_valid && slv_resp_o.w_ready) begin
618	            automatic addr_t mst_port_offset;
619	            automatic addr_t slv_port_offset;
620	            mst_port_offset = AxiMstPortStrbWidth == 1 ? '0 : w_req_q.aw.addr[idx_width(AxiMstPortStrbWidth)-1:0];
621	            slv_port_offset = AxiSlvPortStrbWidth == 1 ? '0 : w_req_q.aw.addr[idx_width(AxiSlvPortStrbWidth)-1:0];
622	
623	            // Serialization
624	            for (int b = 0; b < AxiMstPortStrbWidth; b++)
625	              if ((b >= mst_port_offset) &&
626	                  (b - mst_port_offset < (1 << w_req_q.orig_aw_size)) &&
627	                  (b + slv_port_offset - mst_port_offset < AxiSlvPortStrbWidth)) begin
628	                w_data[b]         = slv_req_i.w.data[8*(b + slv_port_offset - mst_port_offset) +: 8];
629	                w_req_d.w.strb[b] = slv_req_i.w.strb[b + slv_port_offset - mst_port_offset]         ;
630	              end
631	
632	            w_req_d.burst_len = w_req_q.burst_len - 1   ;
633	            w_req_d.w.data    = w_data                  ;
634	            w_req_d.w.last    = (w_req_q.burst_len == 0);
635	            w_req_d.w.user    = slv_req_i.w.user        ;
636	
637	            unique case (w_req_q.aw.burst)
638	              axi_pkg::BURST_INCR: begin
639	                w_req_d.aw.addr = aligned_addr(w_req_q.aw.addr, w_req_q.orig_aw_size) + (1 << w_req_q.orig_aw_size);
640	              end
641	              axi_pkg::BURST_FIXED: begin
642	                w_req_d.aw.addr = w_req_q.aw.addr;
643	              end
644	              default: ;
645	            endcase
646	
647	            unique case (w_state_q)
648	              W_PASSTHROUGH:
649	                // Forward data as soon as we can
650	                w_req_d.w_valid = 1'b1;
651	
652	              W_INCR_UPSIZE:
653	                // Forward when the burst is finished, or after filling up a word
654	                if (w_req_q.burst_len == 0 || (aligned_addr(w_req_d.aw.addr, AxiMstPortMaxSize) != aligned_addr(w_req_q.aw.addr, AxiMstPortMaxSize)))
655	                  w_req_d.w_valid = 1'b1;
656	              default: ;
657	            endcase
658	          end
659	        end
660	
661	        if (mst_req.w_valid && mst_resp.w_ready)
662	          if (w_req_q.burst_len == '1) begin
663	            slv_resp_o.w_ready = 1'b0  ;
664	            w_state_d          = W_IDLE;
665	          end
666	      end
667	      default: ;
668	    endcase
669	
670	    // Can start a new request as soon as w_state_d is W_IDLE
671	    if (w_state_d == W_IDLE) begin
672	      // Reset channels
673	      w_req_d.aw             = '0  ;
674	      w_req_d.aw_valid       = 1'b0;
675	      w_req_d.aw_throw_error = 1'b0;
676	      w_req_d.w              = '0  ;
677	      w_req_d.w_valid        = 1'b0;
678	
679	      if (slv_req_i.aw_valid && slv_req_i.aw.atop[axi_pkg::ATOP_R_RESP]) begin // ATOP with an R response
680	        inject_aw_into_ar_req = 1'b1                 ;
681	        slv_resp_o.aw_ready   = inject_aw_into_ar_gnt;
682	      end else begin // Regular AW
683	        slv_resp_o.aw_ready = 1'b1;
684	      end
685	
686	      // New write request
687	      if (slv_req_i.aw_valid & slv_resp_o.aw_ready) begin
688	        // Default state
689	        w_state_d = W_PASSTHROUGH;
690	
691	        // Save beat
692	        w_req_d.aw       = slv_req_i.aw;
693	        w_req_d.aw_valid = 1'b1        ;
694	
695	        w_req_d.burst_len    = slv_req_i.aw.len ;
696	        w_req_d.orig_aw_size = slv_req_i.aw.size;
697	
698	        unique case (slv_req_i.aw.burst)
699	          axi_pkg::BURST_INCR: begin
700	            // Modifiable transaction
701	            if (modifiable(slv_req_i.aw.cache))
702	              // No need to upsize single-beat transactions.
703	              if (slv_req_i.aw.len != '0) begin
704	                // Evaluate output burst length
705	                automatic addr_t start_addr;
706	                automatic addr_t end_addr;
707	                start_addr = aligned_addr(slv_req_i.aw.addr, AxiMstPortMaxSize);
708	                end_addr   = aligned_addr(beat_addr(slv_req_i.aw.addr,
709	                    slv_req_i.aw.size, slv_req_i.aw.len, slv_req_i.aw.burst, slv_req_i.aw.len),
710	                    AxiMstPortMaxSize);
711	
712	                w_req_d.aw.len  = (end_addr - start_addr) >> AxiMstPortMaxSize;
713	                w_req_d.aw.size = AxiMstPortMaxSize                           ;
714	                w_state_d       = W_INCR_UPSIZE                               ;
715	              end
716	          end
717	
718	          axi_pkg::BURST_FIXED: begin
719	            // Passes through the upsizer without any changes
720	            w_state_d = W_PASSTHROUGH;
721	          end
722	
723	          axi_pkg::BURST_WRAP: begin
724	            // The DW converter does not support this kind of burst ...
725	            w_state_d              = W_PASSTHROUGH;
726	            w_req_d.aw_throw_error = 1'b1         ;
727	
728	            // ... but might if this is a single-beat transaction
729	            if (slv_req_i.aw.len == '0)
730	              w_req_d.aw_throw_error = 1'b0;
731	          end
732	
733	          default: ;
734	        endcase
735	      end
736	    end
737	  end
738	
739	  always_ff @(posedge clk_i or negedge rst_ni) begin
740	    if (!rst_ni) begin
741	      w_state_q <= W_IDLE;
742	      w_req_q   <= '0    ;
743	    end else begin
744	      w_state_q <= w_state_d;
745	      w_req_q   <= w_req_d  ;
746	    end
747	  end
748	
749	endmodule : axi_dw_upsizer
750

