100	    // Returns a byte mask corresponding to the size of the AXI transaction
101	    function automatic axi_addr_t size_mask(axi_pkg::size_t size);
102	      return (axi_addr_t'(1) << size) - 1;
103	    endfunction
104	
105	    /**
106	     * Returns the conversion rate between tgt_size and src_size.
107	     * @return ceil(num_bytes(tgt_size)/num_bytes(src_size))
108	     */
109	    function automatic int unsigned conv_ratio(axi_pkg::size_t tgt_size, axi_pkg::size_t src_size)         ;
110	      return (axi_pkg::num_bytes(tgt_size) + axi_pkg::num_bytes(src_size) - 1)/axi_pkg::num_bytes(src_size);
111	    endfunction: conv_ratio
