236	     * This tasks stores the beats seen by the AR, AW and W channels
237	     * into the respective queues.
238	     */
239	    virtual task automatic store_channels ();
240	      if (slv_port_axi.ar_valid && slv_port_axi.ar_ready)
241	        act_slv_port_ar_queue.push(slv_port_axi.ar_id,
242	          '{
243	            axi_id   : slv_port_axi.ar_id   ,
244	            axi_burst: slv_port_axi.ar_burst,
245	            axi_size : slv_port_axi.ar_size ,
246	            axi_addr : slv_port_axi.ar_addr ,
247	            axi_len  : slv_port_axi.ar_len  ,
248	            axi_cache: slv_port_axi.ar_cache
249	          });
250	
251	      if (slv_port_axi.aw_valid && slv_port_axi.aw_ready) begin
252	        act_slv_port_aw_queue.push_back('{
253	            axi_id   : slv_port_axi.aw_id   ,
254	            axi_burst: slv_port_axi.aw_burst,
255	            axi_size : slv_port_axi.aw_size ,
256	            axi_addr : slv_port_axi.aw_addr ,
257	            axi_len  : slv_port_axi.aw_len  ,
258	            axi_cache: slv_port_axi.aw_cache
259	          });
260	
261	        // This request generates an R response.
262	        // Push this to the AR queue.
263	        if (slv_port_axi.aw_atop[axi_pkg::ATOP_R_RESP])
264	          act_slv_port_ar_queue.push(slv_port_axi.aw_id,
265	            '{
266	              axi_id   : slv_port_axi.aw_id   ,
267	              axi_burst: slv_port_axi.aw_burst,
268	              axi_size : slv_port_axi.aw_size ,
269	              axi_addr : slv_port_axi.aw_addr ,
270	              axi_len  : slv_port_axi.aw_len  ,
271	              axi_cache: slv_port_axi.aw_cache
272	            });
273	      end
274	
275	      if (slv_port_axi.w_valid && slv_port_axi.w_ready)
276	        this.act_slv_port_w_queue.push_back('{
277	            axi_id  : {AxiIdWidth{1'b?}} ,
278	            axi_data: slv_port_axi.w_data,
279	            axi_strb: slv_port_axi.w_strb,
280	            axi_last: slv_port_axi.w_last
281	          });
282	
283	      if (slv_port_axi.r_valid && slv_port_axi.r_ready)
284	        this.act_slv_port_r_queue.push_back('{
285	            axi_id  : slv_port_axi.r_id          ,
286	            axi_data: slv_port_axi.r_data        ,
287	            axi_strb: {AxiSlvPortStrbWidth{1'b?}},
288	            axi_last: slv_port_axi.r_last
289	          });
290	
291	      if (mst_port_axi.ar_valid && mst_port_axi.ar_ready)
292	        act_mst_port_ar_queue.push(mst_port_axi.ar_id,
293	          '{
294	            axi_id   : mst_port_axi.ar_id   ,
295	            axi_burst: mst_port_axi.ar_burst,
296	            axi_size : mst_port_axi.ar_size ,
