299	            axi_cache: mst_port_axi.ar_cache
300	          });
301	
302	      if (mst_port_axi.aw_valid && mst_port_axi.aw_ready) begin
303	        act_mst_port_aw_queue.push_back('{
304	            axi_id   : mst_port_axi.aw_id   ,
305	            axi_burst: mst_port_axi.aw_burst,
306	            axi_size : mst_port_axi.aw_size ,
