308	            axi_len  : mst_port_axi.aw_len  ,
309	            axi_cache: mst_port_axi.aw_cache
310	          });
311	
312	        // This request generates an R response.
313	        // Push this to the AR queue.
314	        if (mst_port_axi.aw_atop[axi_pkg::ATOP_R_RESP])
315	          act_mst_port_ar_queue.push(mst_port_axi.aw_id,
