335	    /*
336	     * This task monitors the master port of the DW converter. Every time it gets an AW transaction,
337	     * it gets checked for its contents against the expected beat on the `exp_aw_queue`.
338	     */
339	    task automatic mon_mst_port_aw ();
340	      exp_ax_t exp_aw;
341	      if (mst_port_axi.aw_valid && mst_port_axi.aw_ready) begin
342	        // Test if the AW beat was expected
343	        exp_aw = this.exp_mst_port_aw_queue.pop_id(mst_port_axi.aw_id);
344	        if (exp_aw.axi_id != mst_port_axi.aw_id) begin
345	          incr_failed_tests(1)                                            ;
346	          $warning("Slave: Unexpected AW with ID: %b", mst_port_axi.aw_id);
347	        end
348	        if (exp_aw.axi_addr != mst_port_axi.aw_addr) begin
349	          incr_failed_tests(1);
350	          $warning("Slave: Unexpected AW with ID: %b and ADDR: %h, exp: %h",
351	            mst_port_axi.aw_id, mst_port_axi.aw_addr, exp_aw.axi_addr);
352	        end
353	        if (exp_aw.axi_len != mst_port_axi.aw_len) begin
354	          incr_failed_tests(1);
355	          $warning("Slave: Unexpected AW with ID: %b and LEN: %h, exp: %h",
356	            mst_port_axi.aw_id, mst_port_axi.aw_len, exp_aw.axi_len);
357	        end
358	        if (exp_aw.axi_burst != mst_port_axi.aw_burst) begin
359	          incr_failed_tests(1);
360	          $warning("Slave: Unexpected AW with ID: %b and BURST: %h, exp: %h",
361	            mst_port_axi.aw_id, mst_port_axi.aw_burst, exp_aw.axi_burst);
362	        end
363	        if (exp_aw.axi_size != mst_port_axi.aw_size) begin
364	          incr_failed_tests(1);
365	          $warning("Slave: Unexpected AW with ID: %b and SIZE: %h, exp: %h",
366	            mst_port_axi.aw_id, mst_port_axi.aw_size, exp_aw.axi_size);
367	        end
368	        if (exp_aw.axi_cache != mst_port_axi.aw_cache) begin
369	          incr_failed_tests(1);
370	          $warning("Slave: Unexpected AW with ID: %b and CACHE: %b, exp: %b",
371	            mst_port_axi.aw_id, mst_port_axi.aw_cache, exp_aw.axi_cache);
372	        end
373	        incr_conducted_tests(6);
374	      end
375	    endtask : mon_mst_port_aw
376	
377	    /*
378	     * This task compares the expected and actual W beats on the master port.
379	     */
380	    task automatic mon_mst_port_w ();
381	      exp_mst_rw_t exp_w, act_w;
382	      while (this.exp_mst_port_w_queue.size() != 0 && this.act_mst_port_w_queue.size() != 0) begin
383	        exp_w = this.exp_mst_port_w_queue.pop_front();
384	        act_w = this.act_mst_port_w_queue.pop_front();
385	        // Do the checks
386	        if (exp_w.axi_data != act_w.axi_data) begin
387	          incr_failed_tests(1);
388	          $warning("Slave: Unexpected W with DATA: %h, exp: %h",
389	            act_w.axi_data, exp_w.axi_data);
390	        end
391	        if (exp_w.axi_strb != act_w.axi_strb) begin
392	          incr_failed_tests(1);
393	          $warning("Slave: Unexpected W with STRB: %h, exp: %h",
394	            act_w.axi_strb, exp_w.axi_strb);
395	        end
396	        if (exp_w.axi_last != act_w.axi_last) begin
397	          incr_failed_tests(1);
398	          $warning("Slave: Unexpected W with LAST: %b, exp: %b",
399	            act_w.axi_last, exp_w.axi_last);
400	        end
401	        incr_conducted_tests(3);
402	      end
403	    endtask : mon_mst_port_w
404	
405	    /*
406	     * This task checks if a B response is allowed on a slave port of the DW converter.
407	     */
408	    task automatic mon_slv_port_b ();
409	      exp_b_t  exp_b;
410	      axi_id_t axi_b_id;
411	      if (slv_port_axi.b_valid && slv_port_axi.b_ready) begin
412	        incr_conducted_tests(1);
413	        axi_b_id = slv_port_axi.b_id;
414	        $display("%0tns > Master: Got last B with ID: %b",
415	          $time, axi_b_id);
416	        if (this.exp_slv_port_b_queue.is_empty()) begin
417	          incr_failed_tests(1)                                                 ;
418	          $warning("Master: unexpected B beat with ID: %b detected!", axi_b_id);
419	        end else begin
420	          exp_b = this.exp_slv_port_b_queue.pop_id(axi_b_id);
421	          if (axi_b_id != exp_b.axi_id) begin
422	            incr_failed_tests(1)                                      ;
423	            $warning("Master: got unexpected B with ID: %b", axi_b_id);
424	          end
425	        end
426	      end
427	    endtask : mon_slv_port_b
