471	    /*
472	     * This task does the R channel monitoring on a slave port. It compares the last flags,
473	     * which are determined by the sequence of previously sent AR vectors.
474	     */
475	    task automatic mon_slv_port_r ();
476	      exp_slv_rw_t exp_r;
477	      if (act_slv_port_r_queue.size() != 0) begin
478	        exp_slv_rw_t act_r = act_slv_port_r_queue[0] ;
479	        if (exp_slv_port_r_queue.queues[act_r.axi_id].size() != 0) begin
480	          exp_r = exp_slv_port_r_queue.pop_id(act_r.axi_id);
481	          void'(act_slv_port_r_queue.pop_front());
482	
483	          // Do the checks
484	          if (exp_r.axi_id != act_r.axi_id) begin
485	            incr_failed_tests(1);
486	            $warning("Slave: Unexpected R with ID: %b",
487	              act_r.axi_id);
488	          end
489	          if (exp_r.axi_last != act_r.axi_last) begin
490	            incr_failed_tests(1);
491	            $warning("Slave: Unexpected R with ID: %b and LAST: %b, exp: %b",
492	              act_r.axi_id, act_r.axi_last, exp_r.axi_last);
493	          end
494	          if (exp_r.axi_data != act_r.axi_data) begin
495	            incr_failed_tests(1);
496	            $warning("Slave: Unexpected R with ID: %b and DATA: %h, exp: %h",
497	              act_r.axi_id, act_r.axi_data, exp_r.axi_data);
498	          end
499	          incr_conducted_tests(3);
500	        end
501	      end
502	    endtask : mon_slv_port_r
503	
504	    // Some tasks to manage bookkeeping of the tests conducted.
505	    task incr_expected_tests(input int unsigned times);
506	      cnt_sem.get()               ;
507	      this.tests_expected += times;
508	      cnt_sem.put()               ;
509	    endtask : incr_expected_tests
510	
511	    task incr_conducted_tests(input int unsigned times);
512	      cnt_sem.get()                ;
513	      this.tests_conducted += times;
514	      cnt_sem.put()                ;
515	    endtask : incr_conducted_tests
516	
517	    task incr_failed_tests(input int unsigned times);
518	      cnt_sem.get()             ;
519	      this.tests_failed += times;
520	      cnt_sem.put()             ;
521	    endtask : incr_failed_tests
522	
523	    /*
524	     * This task invokes the various monitoring tasks. First, all processes that only
525	     * push something in the FIFOs are invoked. After they are finished, the processes
526	     * that pop something from them are invoked.
527	     */
528	    task run();
529	      forever begin
530	        // At every cycle, spawn some monitoring processes.
531	        cycle_start();
532	
533	        // Execute all processes that push something into the queues
534	        PushMon: fork
535	          proc_mst_aw       : mon_slv_port_aw();
536	          proc_mst_ar       : mon_slv_port_ar();
537	          proc_mst_w        : mon_slv_port_w() ;
538	          proc_slv_r        : mon_mst_port_r() ;
539	          proc_store_channel: store_channels() ;
540	        join: PushMon
541	
542	        // These only pop something from the queues
543	        PopMon: fork
544	          proc_slv_aw: mon_mst_port_aw();
545	          proc_mst_b : mon_slv_port_b() ;
546	          proc_slv_ar: mon_mst_port_ar();
547	          proc_mst_r : mon_slv_port_r() ;
548	        join : PopMon
549	
550	        // Check the slave W FIFOs last
551	        proc_check_slv_w: mon_mst_port_w();
552	
553	        cycle_end();
554	      end
555	    endtask : run
556	
557	    task print_result()                                    ;
558	      $info("Simulation has ended!")                       ;
559	      $display("Tests Expected:  %d", this.tests_expected) ;
560	      $display("Tests Conducted: %d", this.tests_conducted);
561	      $display("Tests Failed:    %d", this.tests_failed)   ;
562	      if (tests_failed > 0) begin
563	        $error("Simulation encountered unexpected transactions!");
564	      end
565	    endtask : print_result
