828	    task automatic mon_mst_port_r ();
829	      if (mst_port_axi.r_valid && mst_port_axi.r_ready) begin
830	        // Retrieve the AR requests related to this R beat
831	        exp_ax_t act_mst_ar = act_mst_port_ar_queue.get(mst_port_axi.r_id);
832	        exp_ax_t act_slv_ar = act_slv_port_ar_queue.get(mst_port_axi.r_id);
833	        axi_id_t id         = mst_port_axi.r_id                           ;
834	
835	        // Calculate the offsets inside the incoming word
836	        shortint unsigned mst_port_lower_byte =
837	        axi_pkg::beat_lower_byte(act_mst_ar.axi_addr, act_mst_ar.axi_size, act_mst_ar.axi_len, act_mst_ar.axi_burst, AxiMstPortStrbWidth, mst_port_r_cnt[id]);
838	        shortint unsigned mst_port_upper_byte =
839	        axi_pkg::beat_upper_byte(act_mst_ar.axi_addr, act_mst_ar.axi_size, act_mst_ar.axi_len, act_mst_ar.axi_burst, AxiMstPortStrbWidth, mst_port_r_cnt[id]);
840	        // Pointer inside the incoming word
841	        shortint unsigned mst_port_data_pointer = mst_port_lower_byte;
842	
843	        // Conversion ratio. How many R beats are generated from this incoming R beat.
844	        int unsigned conversion_ratio = axi_pkg::modifiable(act_mst_ar.axi_cache) ? conv_ratio(act_mst_ar.axi_size, act_slv_ar.axi_size) : 1;
845	
846	        // Several R beats generated from this incoming R beat
847	        for (int unsigned beat = 0; beat < conversion_ratio; beat++) begin
848	          exp_slv_rw_t act_slv_r = '0;
849	
850	          // Calculate the offsets inside the outcoming word
851	          shortint unsigned slv_port_lower_byte =
852	          axi_pkg::beat_lower_byte(act_slv_ar.axi_addr, act_slv_ar.axi_size, act_slv_ar.axi_len, act_slv_ar.axi_burst, AxiSlvPortStrbWidth, slv_port_r_cnt[id]);
853	          shortint unsigned slv_port_upper_byte =
854	          axi_pkg::beat_upper_byte(act_slv_ar.axi_addr, act_slv_ar.axi_size, act_slv_ar.axi_len, act_slv_ar.axi_burst, AxiSlvPortStrbWidth, slv_port_r_cnt[id]);
855	
856	          shortint unsigned bytes_copied = 0;
857	
858	          act_slv_r.axi_id   = mst_port_axi.r_id                       ;
859	          act_slv_r.axi_last = slv_port_r_cnt[id] == act_slv_ar.axi_len;
860	          act_slv_r.axi_data = {AxiSlvPortDataWidth{1'b?}}             ;
861	          act_slv_r.axi_strb = {AxiSlvPortStrbWidth{1'b?}}             ;
862	          for (shortint unsigned b = mst_port_data_pointer; b <= mst_port_upper_byte; b++) begin
863	            act_slv_r.axi_data[8*(b + slv_port_lower_byte - mst_port_data_pointer) +: 8] = mst_port_axi.r_data[8*b +: 8];
864	            bytes_copied++;
865	            if (b + slv_port_lower_byte - mst_port_data_pointer == slv_port_upper_byte)
866	              break;
867	          end
868	          this.exp_slv_port_r_queue.push(act_slv_r.axi_id, act_slv_r);
869	          incr_expected_tests(3)                                     ;
870	
871	          // Increment the len counters
872	          slv_port_r_cnt[id]++                 ;
873	          mst_port_data_pointer += bytes_copied;
874	
875	          // Used the whole R beat
876	          if (mst_port_data_pointer == AxiMstPortStrbWidth)
877	            break;
878	          // Finished the R beat
879	          if (act_slv_r.axi_last)
880	            break;
881	        end
882	
883	        // Increment the len counter
884	        mst_port_r_cnt[id]++;
885	
886	        // Pop the AR request from the queues
887	        if (mst_port_r_cnt[id] == act_mst_ar.axi_len + 1) begin
888	          void'(act_mst_port_ar_queue.pop_id(act_mst_ar.axi_id));
889	          mst_port_r_cnt[id] = 0;
890	        end
891	        if (slv_port_r_cnt[id] == act_slv_ar.axi_len + 1) begin
892	          void'(act_slv_port_ar_queue.pop_id(act_slv_ar.axi_id));
893	          slv_port_r_cnt[id] = 0;
894	        end
895	      end
896	    endtask: mon_mst_port_r
