1104	    task automatic mon_slv_port_w ();
1105	      if (act_slv_port_w_queue.size() != 0) begin
1106	        exp_slv_rw_t act_slv_w = act_slv_port_w_queue[0];
1107	
1108	        if (act_mst_port_aw_queue.size() != 0 && act_slv_port_aw_queue.size() != 0) begin
1109	          // Retrieve the AW requests related to this W beat
1110	          exp_ax_t act_mst_aw = act_mst_port_aw_queue[0];
1111	          exp_ax_t act_slv_aw = act_slv_port_aw_queue[0];
1112	
1113	          // Address of the current beat
1114	          axi_addr_t slv_aw_addr = axi_pkg::beat_addr(act_slv_aw.axi_addr, act_slv_aw.axi_size, act_slv_aw.axi_len, act_slv_aw.axi_burst, slv_port_w_cnt);
1115	
1116	          // Calculate the offsets inside the incoming word
1117	          shortint unsigned slv_port_lower_byte =
1118	          axi_pkg::beat_lower_byte(act_slv_aw.axi_addr, act_slv_aw.axi_size, act_slv_aw.axi_len, act_slv_aw.axi_burst, AxiSlvPortStrbWidth, slv_port_w_cnt);
1119	          // Pointer inside the incoming word
1120	          shortint unsigned slv_port_data_pointer = slv_port_lower_byte;
1121	
1122	          // Several W beats generated from this incoming W beat
1123	          int unsigned beat_cnt = conv_ratio(act_slv_aw.axi_size, AxiMstPortMaxSize) - aligned_adjustment(slv_aw_addr, act_slv_aw.axi_size);
1124	
1125	          for (int unsigned beat = 0; beat < beat_cnt; beat++) begin
1126	            exp_mst_rw_t act_mst_w = '0;
1127	
1128	            // Calculate the offsets inside the outcoming word
1129	            shortint unsigned mst_port_lower_byte =
1130	            axi_pkg::beat_lower_byte(act_mst_aw.axi_addr, act_mst_aw.axi_size, act_mst_aw.axi_len, act_mst_aw.axi_burst, AxiMstPortStrbWidth, mst_port_w_cnt);
1131	            shortint unsigned mst_port_upper_byte =
1132	            axi_pkg::beat_upper_byte(act_mst_aw.axi_addr, act_mst_aw.axi_size, act_mst_aw.axi_len, act_mst_aw.axi_burst, AxiMstPortStrbWidth, mst_port_w_cnt);
1133	
1134	            shortint unsigned bytes_copied = 0;
1135	
1136	            act_mst_w.axi_id   = act_mst_aw.axi_id                   ;
1137	            act_mst_w.axi_last = mst_port_w_cnt == act_mst_aw.axi_len;
1138	            act_mst_w.axi_data = '0                                  ;
1139	            for (shortint unsigned b = slv_port_data_pointer; b < AxiSlvPortStrbWidth; b++) begin
1140	              if (b + mst_port_lower_byte - slv_port_data_pointer == AxiMstPortStrbWidth)
1141	                break;
1142	              act_mst_w.axi_data[8*(b + mst_port_lower_byte - slv_port_data_pointer) +: 8] = act_slv_w.axi_data[8*b +: 8];
1143	              act_mst_w.axi_strb[b + mst_port_lower_byte - slv_port_data_pointer]          = act_slv_w.axi_strb[b]       ;
1144	              bytes_copied++;
1145	            end
1146	            // Don't care for the bits outside these accessed by this request
1147	            for (int unsigned b = 0; b < AxiMstPortStrbWidth; b++)
1148	              if (!(mst_port_lower_byte <= b && b <= mst_port_upper_byte))
1149	                act_mst_w.axi_data[8*b +: 8] = {8{1'b?}};
1150	
1151	            this.exp_mst_port_w_queue.push_back(act_mst_w);
1152	            incr_expected_tests(3)                        ;
1153	
1154	            // Increment the len counters
1155	            mst_port_w_cnt++                     ;
1156	            slv_port_data_pointer += bytes_copied;
1157	
1158	            // Used the whole W beat
1159	            if (slv_port_data_pointer == AxiSlvPortStrbWidth)
1160	              break;
1161	          end
1162	
1163	          // Increment the len counter
1164	          slv_port_w_cnt++;
1165	
1166	          // Pop the AW request from the queues
1167	          if (slv_port_w_cnt == act_slv_aw.axi_len + 1) begin
1168	            void'(act_slv_port_aw_queue.pop_front());
1169	            slv_port_w_cnt = 0;
1170	          end
1171	          if (mst_port_w_cnt == act_mst_aw.axi_len + 1) begin
1172	            void'(act_mst_port_aw_queue.pop_front());
1173	            mst_port_w_cnt = 0;
1174	          end
1175	
1176	          // Pop the W request
1177	          void'(act_slv_port_w_queue.pop_front());
1178	        end
1179	      end
1180	    endtask: mon_slv_port_w
