1331	          if (b + slv_port_r_pnt[id] - mst_port_lower_byte == AxiSlvPortStrbWidth)
1332	            break;
1333	          slv_port_r[id].axi_data[8*(b + slv_port_r_pnt[id] - mst_port_lower_byte) +: 8] = mst_port_axi.r_data[8*b +: 8];
1334	          bytes_copied++;
1335	        end
1336	
1337	        // Increment the len counters
1338	        mst_port_r_cnt[id]++              ;
1339	        slv_port_r_pnt[id] += bytes_copied;
1340	
1341	        if (slv_port_r_pnt[id] == slv_port_upper_byte + 1                // Used all bits from the incoming R beat
1342	            || slv_port_r_pnt[id] == AxiSlvPortStrbWidth                 // Filled up an outcoming R beat
1343	            || conv_ratio(act_slv_ar.axi_size, act_mst_ar.axi_size) == 1 // Not downsizing
1344	            || mst_port_axi.r_last                                       // Last beat of an R burst
1345	          ) begin
1346	          // Don't care for the bits outside these accessed by this request
1347	          for (int unsigned b = 0; b < AxiSlvPortStrbWidth; b++)
1348	            if (!(slv_port_lower_byte <= b && b <= slv_port_upper_byte))
1349	              slv_port_r[id].axi_data[8*b +: 8] = {8{1'b?}};
1350	
1351	          this.exp_slv_port_r_queue.push(id, slv_port_r[id]);
1352	          incr_expected_tests(3)                            ;
1353	
1354	          // Increment the len counter
1355	          slv_port_r_cnt[id]++;
1356	
1357	          // Reset R beat
1358	          slv_port_r[id]     = '0;
1359	          slv_port_r_pnt[id] = '1;
1360	        end
1361	
1362	        // Pop the AW request from the queues
1363	        if (slv_port_r_cnt[id] == act_slv_ar.axi_len + 1) begin
1364	          void'(act_slv_port_ar_queue.pop_id(id));
1365	          slv_port_r_cnt[id] = 0;
1366	        end
1367	        if (mst_port_r_cnt[id] == act_mst_ar.axi_len + 1) begin
1368	          void'(act_mst_port_ar_queue.pop_id(id));
1369	          mst_port_r_cnt[id] = 0;
1370	        end
1371	      end
1372	    endtask : mon_mst_port_r
1373	  endclass : axi_dw_downsizer_monitor
1374	
1375	endpackage: tb_axi_dw_pkg
1376

